import React from "react";
import { Button, Card, Container, Form, ListGroup } from "react-bootstrap";
import { useNavigate, useParams } from "react-router";

import { Divider } from "../sub-components/divider";
import { VerticalSpacer } from "../sub-components/vertical-spacer";
import { ENCODE_CREATE_JOB_JWT } from "../utils/jwt-encode-job";
// utils
import { COMPLETE_JOB_CONTEXT } from "../utils/contexts";
import { NOTIFICATIONS } from "../utils/notifications";
import {
  NOTIFICATION_TYPE,
  ROUTE_LINKS,
  // SHUTTLE_SERVICE,
} from "../utils/strings";
import api from "../utils/api";
import { IS_LOGGED_IN } from "../utils/loggedin";

// icons
import { FiEdit } from "react-icons/fi";
import { TbLocationFilled } from "react-icons/tb";
import { FaCheck } from "react-icons/fa";

//modals
import { COMPLETE_VEHICLE_SIZE_MODAL } from "../modals/complete-vehicle-size-modal";
import { COMPLETE_ADD_INFO_MODAL } from "../modals/complete-add-info-modal";
import { COMPLETE_ROUTES_MODAL } from "../modals/complete-routes-modal";
import { ErrorHandling } from "../utils/error-handling";
import { AwaitCallBack } from "../utils/await-callback";

//
import { motion } from "framer-motion";
import { PAGES_VARIANT } from "../utils/animation-variants";
import {
  SECTION_ANIMATION_DELAY,
  SECTION_ANIMATION_DURATION,
} from "../utils/numerics";
import { AnimatedButton } from "../sub-components/animated-button";
import { DATE_FORMATER, TIME_FORMATER } from "../utils/formats";
//
//
export default function CustomerCompleteJob() {
  //
  const { pk } = useParams();

  // navigate
  const navigate = useNavigate();

  //
  const formater = Intl.NumberFormat("en-ZA", {
    style: "currency",
    currency: "zar",
    minimumSignificantDigits: 1,
  });

  // React UseState Hook
  const [job, setJob] = React.useState({});
  const [jobLoaded, setJobLoaded] = React.useState(true);
  const [isQuoteGenerated, setIsQuoteGenerated] = React.useState(false);
  const [generatedQuote, setGeneratedQuote] = React.useState({
    mid_discount: 0,
    referal_discount: 0,
    return_customer_discount: 0,
    base_fee: 0,
    amount_due: 0,
  });
  const [showAdditionalInfoSection, setShowAdditionalInfoSection] =
    React.useState(false);
  const [showRouteSection, setShowRouteSection] = React.useState(false);
  const [showVehicleSizeSection, setShowVehicleSizeSection] =
    React.useState(false);
  const [notificationType, setNotificationType] = React.useState(
    NOTIFICATION_TYPE.none
  );
  const [leadingText, setLeadingText] = React.useState("");
  const [trailingText, setTrailingText] = React.useState("");
  const [disableUI, setDisableUI] = React.useState(false);
  // notification function
  const setNotification = (type, leading, trailing) => {
    setNotificationType((_) => type);
    setLeadingText((_) => leading);
    setTrailingText((_) => trailing);

    //
    const isDisabled =
      type === NOTIFICATION_TYPE.loading ||
      type === NOTIFICATION_TYPE.info ||
      type === NOTIFICATION_TYPE.success;
    // set
    setDisableUI((_) => isDisabled);
  };

  // function to determin
  const pickupDropOff = (list, current) => {
    if (current <= 0) {
      return "Pickup";
    } else if (current > 0 && current < list.length - 1) {
      return "Pickup|Dropoff";
    }
    //
    return "Dropoff";
  };

  // display
  const displayRoutes = (routes) => {
    if (routes)
      return (
        <Form.Group>
          <ListGroup className="rounded-0 gap-1">
            {routes.map((route, i) => {
              return (
                <ListGroup.Item
                  key={i}
                  className="p-2 d-flex flex-row justify-content-between align-items-start gap-2 border-white"
                  style={{ backgroundColor: "var(--primary-color-opacity)" }}
                >
                  <div className="p-0 m-0 d-flex flex-row justify-content-start align-items-start gap-2">
                    <div>
                      <TbLocationFilled color="red" size={15} />
                    </div>
                    <div className="d-flex flex-column justify-content-start align-items-start">
                      <span
                        className="fw-bolder"
                        style={{ fontSize: "0.875rem", color: "grey" }}
                      >
                        {pickupDropOff(route, i)}
                      </span>
                      <span>{route.route_name}</span>
                    </div>
                  </div>
                </ListGroup.Item>
              );
            })}
          </ListGroup>
        </Form.Group>
      );
  };
  // disply prices
  const displayPrices = (jobQuote) => {
    return (
      <React.Fragment>
        <InvoiceItem
          leading={"Base fee"}
          trailing={`${formater.format(jobQuote.base_fee)}`}
        />
        <InvoiceItem
          leading={"Off peak"}
          trailingColor="danger"
          trailing={`${jobQuote.mid_discount > 0 ? "-" : ""}  ${formater.format(
            jobQuote.mid_discount
          )}`}
        />
        <InvoiceItem
          leading={"Return customer"}
          trailingColor="danger"
          trailing={`${
            jobQuote.return_customer_discount > 0 ? "-" : ""
          } ${formater.format(jobQuote.return_customer_discount)}`}
        />

        <Divider />
        <InvoiceItem
          leading={"Amount due"}
          isAmountDue={true}
          trailing={formater.format(jobQuote.amount_due)}
        />
        <Divider />
      </React.Fragment>
    );
  };
  //
  const DriverNoteItem = (leading, trailing) => {
    return (
      <div className="px-3 d-flex flex-column justify-content-start align-items-start">
        <span className="text-muted" style={{ fontWeight: 800 }}>
          {leading}
        </span>
        <span className="fw-normal text-dark">{trailing}</span>
      </div>
    );
  };
  //
  // displayAdditional information `${verifiedJob.job_time}`
  const displayAdditionalInfo = (isLoaded, verifiedJob) => {
    // check if loaded first
    if (isLoaded && verifiedJob.job_date && verifiedJob.job_time) {
      return (
        <React.Fragment>
          <InvoiceItem
            leading={"Job date"}
            trailing={DATE_FORMATER.format(new Date(`${verifiedJob.job_date}`))}
          />
          <InvoiceItem
            leading={"Job time"}
            trailing={TIME_FORMATER.format(
              new Date(`${verifiedJob.job_date} ${verifiedJob.job_time}`)
            )}
          />
          <InvoiceItem
            leading={"Payment method"}
            trailing={
              `${verifiedJob.payment_option}`.toUpperCase().charAt(0) +
              `${verifiedJob.payment_option}`.toLowerCase().slice(1)
            }
          />
          <InvoiceItem leading={"Helper"} trailing={`${verifiedJob.helpers}`} />
          <InvoiceItem leading={"Floors"} trailing={`${verifiedJob.floors}`} />

          {/* {driverNote("Driver note", `${verifiedJob.driver_note}`)} */}
          {/*driver note */}
        </React.Fragment>
      );
    }
  };
  // section vehicle size
  const jobSection = (
    leading,
    onClick,
    showIcon = true,
    disableButton = false
  ) => {
    return (
      <React.Fragment>
        <AnimatedButton
          onClick={disableButton ? null : () => onClick((_) => true)}
        >
          <div className="bg-secondary bg-opacity-75 px-3 py-2 d-flex flex-row justify-content-between align-items-start gap-1">
            <span
              className={`text-white`}
              style={{ fontWeight: "900", fontSize: `${18 / 16}rem` }}
            >
              {leading}
            </span>
            {showIcon ? (
              <div>
                <FiEdit color="white" />
              </div>
            ) : null}
          </div>
        </AnimatedButton>
      </React.Fragment>
    );
  };
  //
  const InvoiceItem = ({
    leading,
    trailing,
    isAmountDue = false,
    leadingColor = "dark",
    trailingColor = "dark",
  }) => {
    return (
      <div className="px-3 d-flex flex-row justify-content-between align-items-center gap-1">
        <span
          className={`text-${leadingColor}`}
          style={{ fontWeight: `${isAmountDue ? "900" : "normal"}` }}
        >
          {leading}
        </span>
        <span
          className={`text-${trailingColor}`}
          style={{
            fontWeight: `${isAmountDue ? "900" : "normal"}`,
            fontSize: isAmountDue ? `${20 / 16}rem` : "",
          }}
        >
          {trailing}
        </span>
      </div>
    );
  };
  //  // loadJob
  const loadJob = (isLoaded, verifiedJob) => {
    if (isLoaded) {
      return (
        <React.Fragment>
          {/*section vehicle Size*/}
          {jobSection(
            "Job vehicle type",
            setShowVehicleSizeSection,
            true,
            disableUI
          )}
          <div className="my-2">
            <InvoiceItem
              leading={"Vehicle size"}
              trailing={`${verifiedJob.vehicle_size} Ton`}
            />
          </div>
          {/*section vehicle Size*/}
          {/*section Routes */}
          {jobSection("Job routes", setShowRouteSection, true, disableUI)}
          {displayRoutes(verifiedJob.routes)}
          {/*section Routes */}
          {/*additional information*/}
          <div className="mb-3">
            {jobSection(
              "Job add-info ",
              setShowAdditionalInfoSection,
              true,
              disableUI
            )}
            {displayAdditionalInfo(isLoaded, verifiedJob)}
          </div>
          {/*additional information*/}
          {/*Quote*/}
          {/* {jobSection("Quote section", () => {}, false)} */}
          <Divider width={"100%"} />
          {generatedQuoteView(isQuoteGenerated, generatedQuote)}
          {/*Quote*/}
          {/*BUtton*/}
          <div className="w-100 mt-3 pb-3 pe-3 d-flex flex-row justify-content-end align-items-center">
            <Button
              variant="outline-primary"
              className="fw-bold border-0 rounded-0 d-flex flex-row justify-content-center align-items-center gap-2"
              disabled={disableUI}
              onClick={async () => {
                //   quote_job: -1,
                createJobFunction(job);
              }}
            >
              Book
              <FaCheck />
            </Button>
          </div>
          {/*BUtton*/}
        </React.Fragment>
      );
    }

    return <></>;
  };

  // load modals
  const loadModals = (loaded, pk) => {
    if (loaded) {
      return (
        <React.Fragment>
          {/*Additional Info*/}
          <COMPLETE_JOB_CONTEXT.Provider
            value={{
              primaryKey: pk,
              show: showAdditionalInfoSection,
              setShow: setShowAdditionalInfoSection,
            }}
          >
            <COMPLETE_ADD_INFO_MODAL />
          </COMPLETE_JOB_CONTEXT.Provider>
          {/*Additional Info
          {/*Vehicle size*/}
          <COMPLETE_JOB_CONTEXT.Provider
            value={{
              primaryKey: pk,
              show: showVehicleSizeSection,
              setShow: setShowVehicleSizeSection,
            }}
          >
            <COMPLETE_VEHICLE_SIZE_MODAL />
          </COMPLETE_JOB_CONTEXT.Provider>
          {/*Vehicle size*/}
          {/*edit routes*/}
          <COMPLETE_JOB_CONTEXT.Provider
            value={{
              primaryKey: pk,
              show: showRouteSection,
              setShow: setShowRouteSection,
            }}
          >
            <COMPLETE_ROUTES_MODAL />
          </COMPLETE_JOB_CONTEXT.Provider>
          {/*edit routes*/}
        </React.Fragment>
      );
    }
  };
  //
  const generatedQuoteView = (generated, quote) => {
    if (generated) return displayPrices(quote);
    return <></>;
  };

  // generate quote
  const generateQFunction = async (request) => {
    // notify that is generating quote
    setIsQuoteGenerated((_) => false);
    setNotification(NOTIFICATION_TYPE.loading, "Loading ...", "");

    // const url
    const url = "jobs/api/job/generate-quote/";
    await api
      .post(url, request.data)
      .then((r) => {
        // check status
        if (r.status === 200) {
          // set notification loading
          setGeneratedQuote((_) => {
            return {
              mid_discount: r.data.mid_discount,
              referal_discount: r.data.referal_discount,
              base_fee: r.data.base_fee,
              amount_due: r.data.amount_due,
              return_customer_discount: r.data.return_customer_discount,
            };
          });
          setIsQuoteGenerated((_) => true);
          setNotification(NOTIFICATION_TYPE.none, "", "");
        }
      })
      .catch((e) => {
        setIsQuoteGenerated((_) => false);
        ErrorHandling(e, setNotification);
      });
  };

  // create Job
  const createJobFunction = React.useCallback(async (payload) => {
    // set notification
    setNotification(NOTIFICATION_TYPE.loading, "Creating ...", "");
    // check if you are logged in
    const [isLoggedin, _] = IS_LOGGED_IN();
    // check if this person is logged in
    if (isLoggedin) {
      // const url
      const url = "jobs/api/job/create/";
      await api
        .post(url, payload)
        .then(async (r) => {
          setNotification(NOTIFICATION_TYPE.success, "Awesome.", "Created");
          await AwaitCallBack(() => {
            let anchor = window.document.createElement("a");
            anchor.href = ROUTE_LINKS.jobs;
            anchor.target = "_self";
            anchor.click();
          }, 2000);
        })
        .catch((e) => ErrorHandling(e, setNotification));
    } else {
      // otherwise
      const message =
        "To complete this job, you must be signed in. we'll navigate you to the sign-in page.";
      setNotification(
        NOTIFICATION_TYPE.info,
        "Dear valued customer. ",
        message
      );
      // sleep
      await AwaitCallBack(() => navigate(ROUTE_LINKS.signin), 6000);
    }
  }, []);
  // retrieve
  const saveAndRetrieveJobComplete = React.useCallback(async (primary_key) => {
    // fetching
    setJobLoaded((_) => false);
    setNotification(NOTIFICATION_TYPE.loading, "Loading ...", "");

    // url
    const url = `quote/job/api/get/${primary_key}/`;
    await api
      .get(url)
      .then(async (r) => {
        // verify status
        if (r.status === 200) {
          const payload = {
            ...r.data,
            hear_about_us: "Referral",
            vehicle_size: Number(r.data.vehicle_size).toFixed(1),
          };
          //set
          setJob((_) => payload);
          ENCODE_CREATE_JOB_JWT(payload);
          setJobLoaded((_) => true);
          await generateQFunction(r);
        }
      })
      .catch((e) => ErrorHandling(e, setNotification));
  }, []);

  //
  React.useEffect(() => {
    // save locally
    saveAndRetrieveJobComplete(pk);
    //
  }, [pk]);

  React.useEffect(() => {
    window.scrollTo(0, 0);
  }, [notificationType]);
  //
  return (
    <motion.section
      className="pb-3 px-3"
      variants={PAGES_VARIANT}
      animate="visible"
      initial="hidden"
      exit="exit"
      transition={{
        duration: SECTION_ANIMATION_DURATION,
        delay: SECTION_ANIMATION_DELAY,
      }}
    >
      <Container className="p-0 d-flex flex-column justify-content-center align-items-center">
        <Card className="dropdown__shadow card__section border-0 rounded-0 ">
          <Card.Header className="text-white bg-secondary rounded-0 border-0 py-2">
            <div className="d-flex flex-column justify-content-center align-items-start">
              <span style={{ fontWeight: "900" }}>CREATE JOB</span>
            </div>
          </Card.Header>
          <Card.Body className="p-0">
            {/*NOTIFICATIONS*/}
            {NOTIFICATIONS(notificationType, leadingText, trailingText)}
            {/*NOTIFICATIONS*/}
            {/*Load Job*/}
            {loadJob(jobLoaded, job)}
            {/*LOad Job*/}
          </Card.Body>
        </Card>
        {/*Modals*/}
        {loadModals(jobLoaded, pk)}
        {/*Modals*/}
      </Container>
      <VerticalSpacer height={`${window.innerHeight / 2}px`} />
    </motion.section>
  );
}
